  1→pub mod config;
  2→pub mod demos;
  3→
  4→use std::collections::VecDeque;
  5→
  6→use config::{PVM_BINARY, label_addr};
  7→use cor24_emulator::EmulatorCore;
  8→use demos::{DEMOS, RUNTIME_SPC};
  9→use gloo::timers::callback::Timeout;
 10→use web_sys::{HtmlElement, HtmlInputElement, HtmlSelectElement};
 11→use yew::prelude::*;
 12→
 13→const BATCH_SIZE: u64 = 50_000;
 14→const TICK_MS: u32 = 25;
 15→
 16→fn pcode_instr_size(op: u8) -> usize {
 17→    match op {
 18→        0x01 | 0x30 | 0x31 | 0x32 | 0x33 | 0x54 | 0x55 | 0x56 => 4,
 19→        0x02 | 0x34 | 0x35 | 0x36 | 0x40 | 0x42 | 0x43 | 0x44 | 0x45 | 0x57 | 0x60 => 2,
 20→        0x58 | 0x59 => 3,
 21→        0x5A => 5,
 22→        _ => 1,
 23→    }
 24→}
 25→
 26→#[derive(Clone, Copy, PartialEq)]
 27→enum AppStatus {
 28→    Ready,
 29→    Running,
 30→    Exited,
 31→}
 32→
 33→pub enum Msg {
 34→    SelectDemo(usize),
 35→    LinkAndRun,
 36→    Stop,
 37→    Tick,
 38→    ToggleSwitch,
 39→    UpdateInput(String),
 40→    SendInput,
 41→    InputKeyDown(KeyboardEvent),
 42→}
 43→
 44→pub struct App {
 45→    selected: usize,
 46→    status: AppStatus,
 47→    emulator: EmulatorCore,
 48→    output: String,
 49→    running: bool,
 50→    halted: bool,
 51→    instruction_count: u64,
 52→    binary_size: usize,
 53→    led_on: bool,
 54→    switch_on: bool,
 55→    uart_input: String,
 56→    uart_rx_queue: VecDeque<u8>,
 57→    _tick_handle: Option<Timeout>,
 58→    output_ref: NodeRef,
 59→    pending_code_base: Option<u32>,
 60→    vm_state_addr: u32,
 61→    vm_loop_addr: u32,
 62→    code_seg_addr: u32,
 63→}
 64→
 65→impl App {
 66→    fn load_vm_binary(&mut self) {
 67→        self.emulator = EmulatorCore::new();
 68→        for (i, &b) in PVM_BINARY.iter().enumerate() {
 69→            self.emulator.write_byte(i as u32, b);
 70→        }
 71→    }
 72→
 73→    fn load_p24_image(&mut self, image: &pa24r::LoadedImage) {
 74→        let load_addr = 0x010000_u32;
 75→        let code_size = image.code.len() as u32;
 76→        let total = code_size + image.data.len() as u32;
 77→
 78→        // Relocate data references: push IMM24 operands in [code_size, total)
 79→        // get load_addr added to become absolute addresses.
 80→        let mut code = image.code.clone();
 81→        let mut i = 0usize;
 82→        while i < code.len() {
 83→            let op = code[i];
 84→            let size = pcode_instr_size(op);
 85→            if op == 0x01 && i + 4 <= code.len() {
 86→                let val = u32::from(code[i + 1])
 87→                    | (u32::from(code[i + 2]) << 8)
 88→                    | (u32::from(code[i + 3]) << 16);
 89→                if val >= code_size && val < total {
 90→                    let abs = val + load_addr;
 91→                    code[i + 1] = abs as u8;
 92→                    code[i + 2] = (abs >> 8) as u8;
 93→                    code[i + 3] = (abs >> 16) as u8;
 94→                }
 95→            }
 96→            i += size;
 97→        }
 98→
 99→        // Write relocated code + data contiguously at load_addr
100→        for (i, &b) in code.iter().chain(image.data.iter()).enumerate() {
101→            self.emulator.write_byte(load_addr + i as u32, b);
102→        }
103→
104→        self.binary_size = total as usize;
105→        self.pending_code_base = Some(load_addr);
106→    }
107→
108→    fn apply_pending_code_base(&mut self) {
109→        if let Some(load_addr) = self.pending_code_base.take() {
110→            // Write "sys halt" at code_seg to stop pvm.s after init
111→            self.emulator.write_byte(self.code_seg_addr, 0x60);
112→            self.emulator.write_byte(self.code_seg_addr + 1, 0x00);
113→
114→            // Run pvm.s init (boots, prints banner)
115→            self.emulator.resume();
116→            self.emulator.run_batch(10_000);
117→
118→            // Discard boot output
119→            self.emulator.clear_uart_output();
120→            self.output.clear();
121→
122→            // Soft reset preserving memory
123→            self.emulator.reset();
124→            self.emulator.set_uart_tx_busy_cycles(0);
125→
126→            // Jump to vm_loop, skip pvm.s init
127→            self.emulator.set_pc(self.vm_loop_addr);
128→            self.emulator.set_reg(3, self.vm_state_addr); // fp
129→
130→            // Patch vm_state for loaded demo
131→            let base = self.vm_state_addr;
132→            // code_base = load_addr
133→            self.emulator.write_byte(base + 18, load_addr as u8);
134→            self.emulator.write_byte(base + 19, (load_addr >> 8) as u8);
135→            self.emulator.write_byte(base + 20, (load_addr >> 16) as u8);
136→            // pc = 0
137→            self.emulator.write_byte(base, 0);
138→            self.emulator.write_byte(base + 1, 0);
139→            self.emulator.write_byte(base + 2, 0);
140→            // status = 0 (running)
141→            self.emulator.write_byte(base + 21, 0);
142→            self.emulator.write_byte(base + 22, 0);
143→            self.emulator.write_byte(base + 23, 0);
144→        }
145→    }
146→
147→    fn collect_uart(&mut self) {
148→        let uart = self.emulator.get_uart_output().to_owned();
149→        if !uart.is_empty() {
150→            self.output.push_str(&uart);
151→            self.emulator.clear_uart_output();
152→        }
153→    }
154→
155→    fn feed_uart_bytes(&mut self) {
156→        while !self.uart_rx_queue.is_empty() {
157→            let status = self.emulator.read_byte(0xFF0101);
158→            if status & 0x01 != 0 {
159→                break;
160→            }
161→            if let Some(byte) = self.uart_rx_queue.pop_front() {
162→                self.emulator.send_uart_byte(byte);
163→            }
164→        }
165→    }
166→
167→    fn schedule_tick(&mut self, ctx: &Context<Self>) {
168→        let link = ctx.link().clone();
169→        self._tick_handle = Some(Timeout::new(TICK_MS, move || {
170→            link.send_message(Msg::Tick);
171→        }));
172→    }
173→
174→    fn check_halted(&mut self, reason: cor24_emulator::StopReason) {
175→        match reason {
176→            cor24_emulator::StopReason::Halted
177→            | cor24_emulator::StopReason::InvalidInstruction(_) => {
178→                self.halted = true;
179→                self.running = false;
180→                self._tick_handle = None;
181→                self.status = AppStatus::Exited;
182→            }
183→            _ => {}
184→        }
185→        // Also check p-code vm_state STATUS field
186→        let st = self.emulator.read_byte(self.vm_state_addr + 21) as u32
187→            | ((self.emulator.read_byte(self.vm_state_addr + 22) as u32) << 8)
188→            | ((self.emulator.read_byte(self.vm_state_addr + 23) as u32) << 16);
189→        if st != 0 {
190→            self.halted = true;
191→            self.running = false;
192→            self._tick_handle = None;
193→            self.status = AppStatus::Exited;
194→        }
195→    }
196→
197→    fn link_and_assemble(&mut self) -> Result<pa24r::LoadedImage, String> {
198→        let demo = &DEMOS[self.selected];
199→
200→        // Parse runtime and demo .spc modules
201→        let rt_module = pl24r::parser::parse(RUNTIME_SPC, "runtime.spc")
202→            .map_err(|e| format!("Parse runtime: {e}"))?;
203→        let demo_module = pl24r::parser::parse(demo.spc_source, "demo.spc")
204→            .map_err(|e| format!("Parse demo: {e}"))?;
205→
206→        // Link: runtime first, then demo (which contains main)
207→        let linked = pl24r::linker::link(&[rt_module, demo_module]).map_err(|errs| {
208→            errs.iter()
209→                .map(|e| e.to_string())
210→                .collect::<Vec<_>>()
211→                .join("; ")
212→        })?;
213→        let spc_text = pl24r::linker::emit(&linked);
214→
215→        // Assemble linked .spc to .p24 binary
216→        let p24_bytes = pa24r::assemble_to_p24(&spc_text).map_err(|errs| {
217→            errs.iter()
218→                .map(|e| format!("line {}: {}", e.line, e.message))
219→                .collect::<Vec<_>>()
220→                .join("; ")
221→        })?;
222→
223→        // Load .p24 binary
224→        pa24r::load_p24(&p24_bytes).map_err(|e| format!("Load p24: {e:?}"))
225→    }
226→}
227→
228→impl Component for App {
229→    type Message = Msg;
230→    type Properties = ();
231→
232→    fn create(_ctx: &Context<Self>) -> Self {
233→        let mut emulator = EmulatorCore::new();
234→        for (i, &b) in PVM_BINARY.iter().enumerate() {
235→            emulator.write_byte(i as u32, b);
236→        }
237→
238→        Self {
239→            selected: 0,
240→            status: AppStatus::Ready,
241→            emulator,
242→            output: String::new(),
243→            running: false,
244→            halted: false,
245→            instruction_count: 0,
246→            binary_size: 0,
247→            led_on: false,
248→            switch_on: false,
249→            uart_input: String::new(),
250→            uart_rx_queue: VecDeque::new(),
251→            _tick_handle: None,
252→            output_ref: NodeRef::default(),
253→            pending_code_base: None,
254→            vm_state_addr: label_addr("vm_state"),
255→            vm_loop_addr: label_addr("vm_loop"),
256→            code_seg_addr: label_addr("code_seg"),
257→        }
258→    }
259→
260→    fn update(&mut self, ctx: &Context<Self>, msg: Self::Message) -> bool {
261→        match msg {
262→            Msg::SelectDemo(idx) => {
263→                if idx < DEMOS.len() {
264→                    self.selected = idx;
265→                    // Stop any running execution
266→                    self.running = false;
267→                    self.halted = false;
268→                    self._tick_handle = None;
269→                    self.output.clear();
270→                    self.instruction_count = 0;
271→                    self.binary_size = 0;
272→                    self.status = AppStatus::Ready;
273→                    self.pending_code_base = None;
274→                }
275→                true
276→            }
277→
278→            Msg::LinkAndRun => {
279→                // Reset state
280→                self.running = false;
281→                self._tick_handle = None;
282→                self.uart_rx_queue.clear();
283→                self.output.clear();
284→                self.instruction_count = 0;
285→                self.halted = false;
286→                self.led_on = false;
287→
288→                // Reload VM binary
289→                self.load_vm_binary();
290→
291→                // Link and assemble
292→                match self.link_and_assemble() {
293→                    Ok(image) => {
294→                        self.load_p24_image(&image);
295→
296→                        // Apply and start running
297→                        self.apply_pending_code_base();
298→                        self.running = true;
299→                        self.status = AppStatus::Running;
300→                        self.emulator.resume();
301→                        self.schedule_tick(ctx);
302→                    }
303→                    Err(e) => {
304→                        self.output = format!("Error: {e}");
305→                        self.status = AppStatus::Exited;
306→                    }
307→                }
308→                true
309→            }
310→
311→            Msg::Stop => {
312→                self.running = false;
313→                self._tick_handle = None;
314→                self.emulator.pause();
315→                self.status = AppStatus::Exited;
316→                true
317→            }
318→
319→            Msg::Tick => {
320→                if !self.running || self.halted {
321→                    return false;
322→                }
323→
324→                self.feed_uart_bytes();
325→                let result = self.emulator.run_batch(BATCH_SIZE);
326→                self.instruction_count += result.instructions_run;
327→                self.collect_uart();
328→
329→                // Check LED state
330→                let led_byte = self.emulator.read_byte(0xFF0200);
331→                self.led_on = led_byte != 0;
332→
333→                self.check_halted(result.reason);
334→
335→                if self.running && !self.halted {
336→                    self.schedule_tick(ctx);
337→                }
338→                true
339→            }
340→
341→            Msg::ToggleSwitch => {
342→                self.switch_on = !self.switch_on;
343→                self.emulator.set_button_pressed(self.switch_on);
344→                true
345→            }
346→
347→            Msg::UpdateInput(val) => {
348→                self.uart_input = val;
349→                false
350→            }
351→
352→            Msg::SendInput => {
353→                let text = std::mem::take(&mut self.uart_input);
354→                for b in text.bytes() {
355→                    self.uart_rx_queue.push_back(b);
356→                }
357→                self.uart_rx_queue.push_back(b'\n');
358→                true
359→            }
360→
361→            Msg::InputKeyDown(e) => {
362→                if e.key() == "Enter" {
363→                    ctx.link().send_message(Msg::SendInput);
364→                }
365→                false
366→            }
367→        }
368→    }
369→
370→    fn rendered(&mut self, _ctx: &Context<Self>, _first_render: bool) {
371→        if let Some(el) = self.output_ref.cast::<HtmlElement>() {
372→            el.set_scroll_top(el.scroll_height());
373→        }
374→    }
375→
376→    fn view(&self, ctx: &Context<Self>) -> Html {
377→        let link = ctx.link();
378→        let demo = &DEMOS[self.selected];
379→
380→        let on_select = link.callback(|e: Event| {
381→            let target: HtmlSelectElement = e.target_unchecked_into();
382→            Msg::SelectDemo(target.value().parse::<usize>().unwrap_or(0))
383→        });
384→
385→        let on_input = link.callback(|e: InputEvent| {
386→            let target: HtmlInputElement = e.target_unchecked_into();
387→            Msg::UpdateInput(target.value())
388→        });
389→
390→        let on_keydown = link.callback(Msg::InputKeyDown);
391→
392→        let (status_text, status_class) = match self.status {
393→            AppStatus::Ready => ("Ready", "status status-ready"),
394→            AppStatus::Running => ("Running", "status status-running"),
395→            AppStatus::Exited => ("Exited", "status status-exited"),
396→        };
397→
398→        let can_run = !self.running;
399→        let is_running = self.running;
400→
401→        html! {
402→            <>
403→                <header>
404→                    <h1>{"Pascal Demos"}</h1>
405→                    <span class="subtitle">{"COR24 P-Code VM"}</span>
406→                </header>
407→
408→                <div class="toolbar">
409→                    <select class="demo-select" onchange={on_select}>
410→                        { for DEMOS.iter().enumerate().map(|(i, d)| html! {
411→                            <option value={i.to_string()} selected={i == self.selected}>
412→                                { d.name }
413→                            </option>
414→                        })}
415→                    </select>
416→                    if can_run {
417→                        <button class="btn btn-run"
418→                                onclick={link.callback(|_| Msg::LinkAndRun)}>
419→                            {"Link & Run"}
420→                        </button>
421→                    } else {
422→                        <button class="btn btn-stop"
423→                                onclick={link.callback(|_| Msg::Stop)}>
424→                            {"Stop"}
425→                        </button>
426→                    }
427→                    <span class={status_class}>{ status_text }</span>
428→                </div>
429→
430→                <div class="grid">
431→                    // Top-left: Pascal Source
432→                    <div class="panel panel-tl">
433→                        <div class="panel-header">{"Pascal Source"}</div>
434→                        <div class="panel-body">
435→                            <pre class="code-display">{ demo.pas_source }</pre>
436→                        </div>
437→                    </div>
438→
439→                    // Top-right: P-Code Assembly
440→                    <div class="panel panel-tr">
441→                        <div class="panel-header">{"P-Code Assembly (.spc)"}</div>
442→                        <div class="panel-body">
443→                            <pre class="code-display">{ demo.spc_source }</pre>
444→                        </div>
445→                    </div>
446→
447→                    // Bottom-left: Output
448→                    <div class="panel panel-bl">
449→                        <div class="panel-header">{"Output"}</div>
450→                        <div class="panel-body">
451→                            <div class="output-text" ref={self.output_ref.clone()}>
452→                                { &self.output }
453→                            </div>
454→                        </div>
455→                        <div class="uart-input">
456→                            <input class="uart-field" type="text"
457→                                   placeholder="UART input..."
458→                                   value={self.uart_input.clone()}
459→                                   oninput={on_input}
460→                                   onkeydown={on_keydown}
461→                                   disabled={!is_running} />
