file.content:
/* Pascal Demos — COR24 panel styles */

/* Header */
header {
    padding: 10px 20px;
    border-bottom: 1px solid var(--surface1);
    display: flex;
    align-items: center;
    gap: 12px;
    flex-shrink: 0;
    background: var(--mantle);
}

header h1 {
    font-size: 20px;
    font-weight: 700;
    color: var(--blue);
    white-space: nowrap;
}

header .subtitle {
    font-size: 13px;
    color: var(--overlay2);
}

/* Toolbar / control bar */
.toolbar {
    display: flex;
    align-items: center;
    gap: 8px;
    padding: 6px 16px;
    border-bottom: 1px solid var(--surface1);
    background: var(--mantle);
    flex-shrink: 0;
}

.demo-select {
    font-family: var(--mono);
    font-size: 12px;
    padding: 4px 8px;
    background: var(--surface0);
    color: var(--text);
    border: 1px solid var(--surface2);
    border-radius: 4px;
    cursor: pointer;
}

.btn {
    font-family: var(--mono);
    font-size: 13px;
    padding: 4px 14px;
    border: 1px solid var(--surface2);
    border-radius: 4px;
    cursor: pointer;
    background: var(--surface0);
    color: var(--text);
    transition: background 0.15s;
}

.btn:hover:not(:disabled) {
    background: var(--surface1);
}

.btn:disabled {
    opacity: 0.4;
    cursor: default;
}

.btn-run {
    color: var(--green);
    border-color: var(--green);
}

.btn-stop {
    color: var(--red);
    border-color: var(--red);
}

.status {
    font-size: 13px;
    font-weight: 600;
    margin-left: auto;
}

.status-ready { color: var(--yellow); }
.status-running { color: var(--green); }
.status-exited { color: var(--overlay2); }

/* Four-panel grid */
.grid {
    display: grid;
    grid-template-columns: 1fr 1fr;
    grid-template-rows: 1fr 1fr;
    flex: 1;
    overflow: hidden;
    min-height: 0;
}

.panel {
    display: flex;
    flex-direction: column;
    overflow: hidden;
    min-height: 0;
}

.panel-tl { border-right: 1px solid var(--surface1); border-bottom: 1px solid var(--surface1); }
.panel-tr { border-bottom: 1px solid var(--surface1); }
.panel-bl { border-right: 1px solid var(--surface1); }
.panel-br { }

.panel-header {
    font-size: 11px;
    font-weight: 600;
    color: var(--blue);
    text-transform: uppercase;
    letter-spacing: 0.06em;
    padding: 6px 12px;
    border-bottom: 1px solid var(--surface1);
    background: var(--mantle);
    flex-shrink: 0;
}

.panel-body {
    flex: 1;
    overflow-y: auto;
    padding: 8px 12px;
    min-height: 0;
}

/* Code display */
.code-display {
    font-size: 13px;
    line-height: 1.5;
    white-space: pre;
    color: var(--subtext1);
    tab-size: 4;
}

/* Output console */
.output-text {
    font-size: 13px;
    line-height: 1.4;
    white-space: pre-wrap;
    word-break: break-all;
    color: var(--subtext1);
    background: var(--crust);
    padding: 8px;
    border-radius: 4px;
    flex: 1;
    min-height: 40px;
    overflow-y: auto;
}

.uart-input {
    display: flex;
    gap: 4px;
    padding: 6px 12px;
    flex-shrink: 0;
    border-top: 1px solid var(--surface1);
}

.uart-field {
    flex: 1;
    font-family: var(--mono);
    font-size: 13px;
    padding: 4px 8px;
    background: var(--crust);
    color: var(--text);
    border: 1px solid var(--surface2);
    border-radius: 4px;
}

.uart-field::placeholder {
    color: var(--overlay0);
}

.uart-field:focus {
    outline: none;
    border-color: var(--blue);
}

.btn-send {
    color: var(--sapphire);
    border-color: var(--sapphire);
}

/* Hardware panel */
.hw-section {
    margin-bottom: 12px;
}

.hw-label {
    font-size: 11px;
    color: var(--overlay1);
    text-transform: uppercase;
    letter-spacing: 0.05em;
    margin-bottom: 4px;
}

.hw-row {
    display: flex;
    align-items: center;
    gap: 8px;
    font-size: 13px;
    padding: 2px 0;
}

.led-indicator {
    display: inline-block;
    width: 14px;
    height: 14px;
    border-radius: 50%;
    border: 2px solid var(--surface2);
    background: var(--surface0);
    flex-shrink: 0;
}

.led-indicator.led-on {
    background: var(--green);
    border-color: var(--green);
    box-shadow: 0 0 6px var(--green);
}

.switch-btn {
    font-family: var(--mono);
    font-size: 11px;
    padding: 2px 10px;
    background: var(--surface0);
    color: var(--overlay2);
    border: 1px solid var(--surface2);
    border-radius: 3px;
    cursor: pointer;
}

.switch-btn:hover {
    background: var(--surface1);
}

.switch-btn.switch-on {
    color: var(--peach);
    border-color: var(--peach);
}

.hw-stat {
    font-size: 12px;
    color: var(--overlay1);
    font-variant-numeric: tabular-nums;
}

.hw-stat-val {
    color: var(--text);
}

/* Footer */
footer {
    display: flex;
    align-items: center;
    gap: 8px;
    padding: 4px 20px;
    font-size: 0.8em;
    color: var(--overlay0);
    border-top: 1px solid var(--surface1);
    flex-shrink: 0;
}

footer .sep { color: var(--surface2); }

