  1→#include "lexer.c"
  2→#include "parser.h"
  3→
  4→/* Forward declarations for recursive descent */
  5→int parse_expression(void);
  6→void parse_stmt(void);
  7→
  8→/* --- String helpers --- */
  9→
 10→void str_copy(char *dst, char *src) {
 11→    int i;
 12→    i = 0;
 13→    while (src[i] != 0) {
 14→        dst[i] = src[i];
 15→        i = i + 1;
 16→    }
 17→    dst[i] = 0;
 18→}
 19→
 20→/* --- Error handling --- */
 21→
 22→void error(char *msg) {
 23→    printf("error line %d: %s (got %s)\n", tok_line, msg, token_name(tok_type));
 24→    parse_error = 1;
 25→}
 26→
 27→void expect(int tok) {
 28→    if (tok_type != tok) {
 29→        printf("error line %d: expected %s, got %s\n",
 30→               tok_line, token_name(tok), token_name(tok_type));
 31→        parse_error = 1;
 32→        return;
 33→    }
 34→    next_token();
 35→}
 36→
 37→int accept(int tok) {
 38→    if (tok_type == tok) {
 39→        next_token();
 40→        return 1;
 41→    }
 42→    return 0;
 43→}
 44→
 45→/* --- .spc emission --- */
 46→
 47→int new_label(void) {
 48→    int l;
 49→    l = label_count;
 50→    label_count = label_count + 1;
 51→    return l;
 52→}
 53→
 54→/* --- Symbol table --- */
 55→
 56→char *sym_name_at(int i) {
 57→    int off;
 58→    off = i * MAX_NAME;
 59→    return &sym_name[off];
 60→}
 61→
 62→int sym_lookup(char *name) {
 63→    int i;
 64→    i = 0;
 65→    while (i < sym_count) {
 66→        if (strcmp(sym_name_at(i), name) == 0) return i;
 67→        i = i + 1;
 68→    }
 69→    return -1;
 70→}
 71→
 72→int sym_add(char *name, int kind, int type, int value) {
 73→    int idx;
 74→    if (sym_lookup(name) >= 0) {
 75→        printf("error line %d: duplicate symbol '%s'\n", tok_line, name);
 76→        parse_error = 1;
 77→        return -1;
 78→    }
 79→    if (sym_count >= MAX_SYMBOLS) {
 80→        error("too many symbols");
 81→        return -1;
 82→    }
 83→    idx = sym_count;
 84→    str_copy(sym_name_at(idx), name);
 85→    sym_kind[idx] = kind;
 86→    sym_type_id[idx] = type;
 87→    sym_value[idx] = value;
 88→    sym_count = sym_count + 1;
 89→    return idx;
 90→}
 91→
 92→/* --- Expression parsing (returns type) --- */
 93→
 94→int parse_factor(void) {
 95→    int idx;
 96→    int type;
 97→    char name[MAX_NAME];
 98→
 99→    if (tok_type == TOK_INT_LIT) {
100→        printf("    push %d\n", tok_int_val);
101→        next_token();
102→        return TYPE_INTEGER;
103→    }
104→
105→    if (tok_type == TOK_TRUE) {
106→        printf("    push 1\n");
107→        next_token();
108→        return TYPE_BOOLEAN;
109→    }
110→
111→    if (tok_type == TOK_FALSE) {
112→        printf("    push 0\n");
113→        next_token();
114→        return TYPE_BOOLEAN;
115→    }
116→
117→    if (tok_type == TOK_NOT) {
118→        next_token();
119→        type = parse_factor();
120→        if (type != TYPE_BOOLEAN) error("not requires boolean");
121→        printf("    push 0\n");
122→        printf("    eq\n");
123→        return TYPE_BOOLEAN;
124→    }
125→
126→    if (tok_type == TOK_LPAREN) {
127→        next_token();
128→        type = parse_expression();
129→        expect(TOK_RPAREN);
130→        return type;
131→    }
132→
133→    if (tok_type == TOK_IDENT) {
134→        str_copy(name, tok_lexeme);
135→        next_token();
136→        idx = sym_lookup(name);
137→        if (idx < 0) {
138→            printf("error line %d: undeclared '%s'\n", tok_line, name);
139→            parse_error = 1;
140→            return TYPE_INTEGER;
141→        }
142→        if (sym_kind[idx] == SYM_CONST) {
143→            printf("    push %d\n", sym_value[idx]);
144→        } else {
145→            printf("    loadg %s\n", sym_name_at(idx));
146→        }
147→        return sym_type_id[idx];
148→    }
149→
150→    error("expected expression");
151→    return TYPE_INTEGER;
152→}
153→
154→int parse_term(void) {
155→    int type;
156→    int op;
157→    int rtype;
158→
159→    type = parse_factor();
160→
161→    while (tok_type == TOK_STAR || tok_type == TOK_DIV ||
162→           tok_type == TOK_MOD || tok_type == TOK_AND) {
163→        op = tok_type;
164→        next_token();
165→        rtype = parse_factor();
166→
167→        if (op == TOK_STAR) {
168→            if (type != TYPE_INTEGER || rtype != TYPE_INTEGER)
169→                error("* requires integers");
170→            printf("    mul\n");
171→        } else if (op == TOK_DIV) {
172→            if (type != TYPE_INTEGER || rtype != TYPE_INTEGER)
173→                error("div requires integers");
174→            printf("    div\n");
175→        } else if (op == TOK_MOD) {
176→            if (type != TYPE_INTEGER || rtype != TYPE_INTEGER)
177→                error("mod requires integers");
178→            printf("    mod\n");
179→        } else {
180→            if (type != TYPE_BOOLEAN || rtype != TYPE_BOOLEAN)
181→                error("and requires booleans");
182→            printf("    and\n");
183→            type = TYPE_BOOLEAN;
184→        }
185→    }
186→
187→    return type;
188→}
189→
190→int parse_simple_expr(void) {
191→    int negate;
192→    int type;
193→    int op;
194→    int rtype;
195→
196→    negate = 0;
197→    if (tok_type == TOK_PLUS) {
198→        next_token();
199→    } else if (tok_type == TOK_MINUS) {
200→        next_token();
201→        negate = 1;
202→    }
203→
204→    type = parse_term();
205→
206→    if (negate) {
207→        if (type != TYPE_INTEGER) error("unary minus requires integer");
208→        printf("    neg\n");
209→    }
210→
211→    while (tok_type == TOK_PLUS || tok_type == TOK_MINUS || tok_type == TOK_OR) {
212→        op = tok_type;
213→        next_token();
214→        rtype = parse_term();
215→
216→        if (op == TOK_PLUS) {
217→            if (type != TYPE_INTEGER || rtype != TYPE_INTEGER)
218→                error("+ requires integers");
219→            printf("    add\n");
220→        } else if (op == TOK_MINUS) {
221→            if (type != TYPE_INTEGER || rtype != TYPE_INTEGER)
222→                error("- requires integers");
223→            printf("    sub\n");
224→        } else {
225→            if (type != TYPE_BOOLEAN || rtype != TYPE_BOOLEAN)
226→                error("or requires booleans");
227→            printf("    or\n");
228→            type = TYPE_BOOLEAN;
229→        }
230→    }
231→
232→    return type;
233→}
234→
235→int parse_expression(void) {
236→    int type;
237→    int op;
238→    int rtype;
239→
240→    type = parse_simple_expr();
241→
242→    if (tok_type == TOK_EQ || tok_type == TOK_NEQ ||
243→        tok_type == TOK_LT || tok_type == TOK_LE ||
244→        tok_type == TOK_GT || tok_type == TOK_GE) {
245→        op = tok_type;
246→        next_token();
247→        rtype = parse_simple_expr();
248→
249→        if (type != rtype) error("type mismatch in comparison");
250→
251→        if (op == TOK_EQ) printf("    eq\n");
252→        else if (op == TOK_NEQ) printf("    ne\n");
253→        else if (op == TOK_LT) printf("    lt\n");
254→        else if (op == TOK_LE) printf("    le\n");
255→        else if (op == TOK_GT) printf("    gt\n");
256→        else if (op == TOK_GE) printf("    ge\n");
257→
258→        return TYPE_BOOLEAN;
259→    }
260→
261→    return type;
262→}
263→
264→/* --- Statement parsing --- */
265→
266→void parse_compound_stmt(void) {
267→    expect(TOK_BEGIN);
268→    parse_stmt();
269→    while (tok_type == TOK_SEMI) {
270→        next_token();
271→        parse_stmt();
272→    }
273→    expect(TOK_END);
274→}
275→
276→void parse_if_stmt(void) {
277→    int type;
278→    int l_else;
279→    int l_end;
280→
281→    next_token(); /* consume IF */
282→    type = parse_expression();
283→    if (type != TYPE_BOOLEAN) error("if condition must be boolean");
284→
285→    l_else = new_label();
286→    l_end = new_label();
287→
288→    printf("    jz L%d\n", l_else);
289→
290→    expect(TOK_THEN);
291→    parse_stmt();
292→
293→    if (tok_type == TOK_ELSE) {
294→        printf("    jmp L%d\n", l_end);
295→        printf("L%d:\n", l_else);
296→        next_token();
297→        parse_stmt();
298→        printf("L%d:\n", l_end);
299→    } else {
300→        printf("L%d:\n", l_else);
301→    }
302→}
303→
304→void parse_while_stmt(void) {
305→    int type;
306→    int l_start;
307→    int l_end;
308→
309→    next_token(); /* consume WHILE */
310→    l_start = new_label();
311→    l_end = new_label();
312→
313→    printf("L%d:\n", l_start);
314→
315→    type = parse_expression();
316→    if (type != TYPE_BOOLEAN) error("while condition must be boolean");
317→
318→    printf("    jz L%d\n", l_end);
319→
320→    expect(TOK_DO);
321→    parse_stmt();
322→
323→    printf("    jmp L%d\n", l_start);
324→    printf("L%d:\n", l_end);
325→}
