 81→        let mut i = 0usize;
 82→        while i < code.len() {
 83→            let op = code[i];
 84→            let size = pcode_instr_size(op);
 85→            if op == 0x01 && i + 4 <= code.len() {
 86→                let val = u32::from(code[i + 1])
 87→                    | (u32::from(code[i + 2]) << 8)
 88→                    | (u32::from(code[i + 3]) << 16);
 89→                if val >= code_size && val < total {
 90→                    let abs = val + load_addr;
 91→                    code[i + 1] = abs as u8;
 92→                    code[i + 2] = (abs >> 8) as u8;
 93→                    code[i + 3] = (abs >> 16) as u8;
 94→                }
 95→            }
 96→            i += size;
 97→        }
 98→
 99→        // Write relocated code + data contiguously at load_addr
100→        for (i, &b) in code.iter().chain(image.data.iter()).enumerate() {
101→            self.emulator.write_byte(load_addr + i as u32, b);
102→        }
103→
104→        self.binary_size = total as usize;
105→        self.pending_code_base = Some(load_addr);
106→    }
107→
108→    fn apply_pending_code_base(&mut self) {
109→        if let Some(load_addr) = self.pending_code_base.take() {
110→            // Write "sys halt" at code_seg to stop pvm.s after init
111→            self.emulator.write_byte(self.code_seg_addr, 0x60);
112→            self.emulator.write_byte(self.code_seg_addr + 1, 0x00);
113→
114→            // Run pvm.s init (boots, prints banner)
115→            self.emulator.resume();
116→            self.emulator.run_batch(10_000);
117→
118→            // Discard boot output
119→            self.emulator.clear_uart_output();
120→            self.output.clear();
121→
122→            // Soft reset preserving memory
123→            self.emulator.reset();
124→            self.emulator.set_uart_tx_busy_cycles(0);
125→
126→            // Jump to vm_loop, skip pvm.s init
127→            self.emulator.set_pc(self.vm_loop_addr);
128→            self.emulator.set_reg(3, self.vm_state_addr); // fp
129→
130→            // Patch vm_state for loaded demo
131→            let base = self.vm_state_addr;
132→            // code_base = load_addr
133→            self.emulator.write_byte(base + 18, load_addr as u8);
134→            self.emulator.write_byte(base + 19, (load_addr >> 8) as u8);
135→            self.emulator.write_byte(base + 20, (load_addr >> 16) as u8);
136→            // pc = 0
137→            self.emulator.write_byte(base, 0);
138→            self.emulator.write_byte(base + 1, 0);
139→            self.emulator.write_byte(base + 2, 0);
140→            // status = 0 (running)
141→            self.emulator.write_byte(base + 21, 0);
142→            self.emulator.write_byte(base + 22, 0);
143→            self.emulator.write_byte(base + 23, 0);
144→        }
145→    }
146→
147→    fn collect_uart(&mut self) {
148→        let uart = self.emulator.get_uart_output().to_owned();
149→        if !uart.is_empty() {
150→            self.output.push_str(&uart);
151→            self.emulator.clear_uart_output();
152→        }
153→    }
154→
155→    fn feed_uart_bytes(&mut self) {
156→        while !self.uart_rx_queue.is_empty() {
157→            let status = self.emulator.read_byte(0xFF0101);
158→            if status & 0x01 != 0 {
159→                break;
160→            }
161→            if let Some(byte) = self.uart_rx_queue.pop_front() {
162→                self.emulator.send_uart_byte(byte);
163→            }
164→        }
165→    }
166→
167→    fn schedule_tick(&mut self, ctx: &Context<Self>) {
168→        let link = ctx.link().clone();
169→        self._tick_handle = Some(Timeout::new(TICK_MS, move || {
170→            link.send_message(Msg::Tick);
171→        }));
172→    }
173→
174→    fn check_halted(&mut self, reason: cor24_emulator::StopReason) {
175→        match reason {
176→            cor24_emulator::StopReason::Halted
177→            | cor24_emulator::StopReason::InvalidInstruction(_) => {
178→                self.halted = true;
179→                self.running = false;
180→                self._tick_handle = None;
181→                self.status = AppStatus::Exited;
182→            }
183→            _ => {}
184→        }
185→        // Also check p-code vm_state STATUS field
186→        let st = self.emulator.read_byte(self.vm_state_addr + 21) as u32
187→            | ((self.emulator.read_byte(self.vm_state_addr + 22) as u32) << 8)
188→            | ((self.emulator.read_byte(self.vm_state_addr + 23) as u32) << 16);
189→        if st != 0 {
190→            self.halted = true;
191→            self.running = false;
192→            self._tick_handle = None;
193→            self.status = AppStatus::Exited;
194→        }
195→    }
196→
197→    fn link_and_assemble(&mut self) -> Result<pa24r::LoadedImage, String> {
198→        let demo = &DEMOS[self.selected];
199→
200→        // Parse runtime and demo .spc modules
201→        let rt_module = pl24r::parser::parse(RUNTIME_SPC, "runtime.spc")
202→            .map_err(|e| format!("Parse runtime: {e}"))?;
203→        let demo_module = pl24r::parser::parse(demo.spc_source, "demo.spc")
204→            .map_err(|e| format!("Parse demo: {e}"))?;
205→
206→        // Link: runtime first, then demo (which contains main)
207→        let linked = pl24r::linker::link(&[rt_module, demo_module]).map_err(|errs| {
208→            errs.iter()
209→                .map(|e| e.to_string())
210→                .collect::<Vec<_>>()
211→                .join("; ")
212→        })?;
213→        let spc_text = pl24r::linker::emit(&linked);
214→
215→        // Assemble linked .spc to .p24 binary
216→        let p24_bytes = pa24r::assemble_to_p24(&spc_text).map_err(|errs| {
217→            errs.iter()
218→                .map(|e| format!("line {}: {}", e.line, e.message))
219→                .collect::<Vec<_>>()
220→                .join("; ")
221→        })?;
222→
223→        // Load .p24 binary
224→        pa24r::load_p24(&p24_bytes).map_err(|e| format!("Load p24: {e:?}"))
225→    }
226→}
