            AppStatus::Ready => ("Ready", "status status-ready"),
            AppStatus::Compiling => ("Compiling", "status status-compiling"),
            AppStatus::Linking => ("Linking", "status status-linking"),
            AppStatus::Running => ("Running", "status status-running"),
